t.script:
(function () {
    'use strict';
    document.addEventListener('DOMContentLoaded', function () {
        var searchInput = document.getElementById('pv-hha-search');
        var listEl      = document.getElementById('pv-hha-list');
        var noResults   = document.getElementById('pv-hha-no-results');
        var dropdownEl  = document.getElementById('pv-hha-selector');
        if (!searchInput || !listEl || !dropdownEl) return;

        // ── Prevent the search input from closing the dropdown ──────
        // Without data-bs-auto-close="outside", Bootstrap closes the
        // dropdown on ANY click inside it. We stop propagation on the
        // search wrap so typing/clicking in the box keeps it open.
        var searchWrap = searchInput.closest('.pv-hha-search-wrap');
        if (searchWrap) {
            searchWrap.addEventListener('click', function (e) {
                e.stopPropagation();
            });
        }

        // ── Live filter ─────────────────────────────────────────────
        function getOptions() {
            return listEl.querySelectorAll('a.pv-hha-option');
        }

        searchInput.addEventListener('input', function () {
            var q = this.value.trim().toLowerCase();
            var visible = 0;
            getOptions().forEach(function (el) {
                var label = (el.getAttribute('data-label') || '').toLowerCase();
                var show  = !q || label.indexOf(q) !== -1;
                el.style.display = show ? '' : 'none';
                if (show) visible++;
            });
            noResults.classList.toggle('d-none', visible > 0);
        });

        // ── Close dropdown immediately when an HHA option is clicked ─
        // The page will navigate, but this gives instant visual feedback
        getOptions().forEach(function (el) {
            el.addEventListener('click', function () {
                var bsDropdown = bootstrap.Dropdown.getInstance(
                    dropdownEl.querySelector('[data-bs-toggle="dropdown"]')
                );
                if (bsDropdown) bsDropdown.hide();
            });
        });

        // ── Reset search when dropdown closes ───────────────────────
        dropdownEl.addEventListener('hidden.bs.dropdown', function () {
            searchInput.value = '';
            getOptions().forEach(function (el) { el.style.display = ''; });
            noResults.classList.add('d-none');
        });

        // ── Auto-focus search when dropdown opens ───────────────────
        dropdownEl.addEventListener('shown.bs.dropdown', function () {
            searchInput.focus();
        });
    });
})();

// ============================================================
// CONTEXT FILTER – cascading State → County → Locations
// ============================================================
(function () {
    'use strict';
    document.addEventListener('DOMContentLoaded', function () {

        var geoDataEl = document.getElementById('pv-ctx-geo-data');
        if (!geoDataEl) return;
        var geoData = {};
        try { geoData = JSON.parse(geoDataEl.textContent || '{}'); } catch (e) { return; }

        var filterBar    = document.querySelector('.pv-ctx-filter-bar');
        if (!filterBar) return;

        var stateSelect  = document.getElementById('ctx-state-select');
        var countySelect = document.getElementById('ctx-county-select');
        var yearSelect   = document.getElementById('ctx-year-select');
        var payerSelect  = document.getElementById('ctx-payer-select');
        var locList      = document.getElementById('ctx-loc-list');
        var locSummary   = document.getElementById('ctx-loc-summary');
        var locSearch    = document.getElementById('ctx-loc-search');
        var locEmpty     = document.getElementById('ctx-loc-empty');
        var locClear     = document.getElementById('ctx-loc-clear');
        var locDone      = document.getElementById('ctx-loc-done');
        var applyBtn     = document.getElementById('ctx-apply-btn');
        var locDropEl    = document.getElementById('ctx-loc-dropdown');

        if (!stateSelect || !countySelect || !locList) return;

        // Read server-rendered initial values from data attrs
        var initState   = filterBar.dataset.state     || '';
        var initCounty  = filterBar.dataset.county    || '';
        var initLocs    = filterBar.dataset.locations || '';
        var initHhaId   = filterBar.dataset.hhaId     || 'all';
        var initPageKey = filterBar.dataset.pageKey   || 'overview';
        var initTabKey  = filterBar.dataset.tabKey    || '';

        // Selected cities: Set of city name strings
        var selectedCities = new Set();
        if (initLocs) {
            initLocs.split(',').forEach(function (s) {
                s = s.trim();
                if (s) selectedCities.add(s);
            });
        }

        // ── Populate county select from geoData ──────────────────
        function populateCounties(state, selCounty) {
            countySelect.innerHTML = 'All Counties';
            if (state && geoData[state]) {
                Object.keys(geoData[state]).sort().forEach(function (co) {
                    var opt = document.createElement('option');
                    opt.value = co;
                    opt.textContent = co || '(Unknown)';
                    if (co === selCounty) opt.selected = true;
                    countySelect.appendChild(opt);
                });
            }
        }

        // ── Get city list for state + county ─────────────────────
        // geoData structure: {state: {county: [city1, city2, ...]}}
        function getCities(state, county) {
            if (!state || !geoData[state]) return [];
            var cities = [];
            if (county && geoData[state][county]) {
                cities = geoData[state][county].slice();
            } else {
                // All cities in the selected state
                var seen = {};
                Object.values(geoData[state]).forEach(function (arr) {
                    arr.forEach(function (c) {
                        if (!seen[c]) { seen[c] = true; cities.push(c); }
                    });
                });
                cities.sort();
            }
            return cities;
        }

        // ── Render city checkbox list ─────────────────────────────
        function renderLocList(state, county) {
            locList.innerHTML = '';
            var cities = getCities(state, county);

            if (!state) {
                locEmpty.textContent = 'Select a state to see locations';
                locEmpty.style.display = '';
                return;
            }
            if (cities.length === 0) {
                locEmpty.textContent = 'No locations found';
                locEmpty.style.display = '';
                return;
            }
            locEmpty.style.display = 'none';

            // "Select All" row
            locList.appendChild(makeLocItem(null, 'All Locations', true));

            cities.forEach(function (city) {
                locList.appendChild(makeLocItem(city, city, false));
            });

            updateAllCheckbox();
            updateLocSummary();
        }

        // city is a string (or null for "All"), label is display text
        function makeLocItem(city, label, isAll) {
            var item = document.createElement('label');
            item.className = 'pv-ctx-loc-item' + (isAll ? ' pv-ctx-loc-all' : '');
            item.setAttribute('data-label', label.toLowerCase());

            var cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.className = 'pv-ctx-loc-cb' + (isAll ? '' : ' pv-ctx-loc-ind');
            if (isAll) {
                cb.id = 'ctx-loc-cb-all';
            } else {
                cb.value = city;
                cb.checked = selectedCities.has(city);
            }

            var span = document.createElement('span');
            span.textContent = label;

            item.appendChild(cb);
            item.appendChild(span);
            return item;
        }

        function updateAllCheckbox() {
            var allCb = document.getElementById('ctx-loc-cb-all');
            if (!allCb) return;
            var indCbs = locList.querySelectorAll('.pv-ctx-loc-ind');
            var checked = Array.prototype.filter.call(indCbs, function (c) { return c.checked; }).length;
            allCb.checked = indCbs.length > 0 && checked === indCbs.length;
            allCb.indeterminate = checked > 0 && checked < indCbs.length;
        }

        function updateLocSummary() {
            locSummary.textContent = selectedCities.size > 0
                ? selectedCities.size + ' selected'
                : 'All Locations';
        }

        // ── State change ──────────────────────────────────────────
        stateSelect.addEventListener('change', function () {
            selectedCities.clear();
            populateCounties(this.value, '');
            renderLocList(this.value, '');
        });

        // ── County change ─────────────────────────────────────────
        countySelect.addEventListener('change', function () {
            selectedCities.clear();
            renderLocList(stateSelect.value, this.value);
        });

        // ── Location checkbox clicks ──────────────────────────────
        locList.addEventListener('change', function (e) {
            var cb = e.target;
            if (!cb.classList.contains('pv-ctx-loc-cb')) return;

            if (cb.id === 'ctx-loc-cb-all') {
                locList.querySelectorAll('.pv-ctx-loc-ind').forEach(function (c) {
                    c.checked = cb.checked;
                    if (cb.checked) selectedCities.add(c.value);
                    else selectedCities.delete(c.value);
                });
            } else {
                if (cb.checked) selectedCities.add(cb.value);
                else selectedCities.delete(cb.value);
                updateAllCheckbox();
            }
            updateLocSummary();
        });

        // ── Location search ───────────────────────────────────────
        if (locSearch) {
            var searchWrap = locSearch.closest('.pv-ctx-loc-search-wrap');
            if (searchWrap) {
                searchWrap.addEventListener('click', function (e) { e.stopPropagation(); });
            }
            locSearch.addEventListener('input', function () {
                var q = this.value.trim().toLowerCase();
                locList.querySelectorAll('.pv-ctx-loc-item:not(.pv-ctx-loc-all)').forEach(function (item) {
                    var lbl = item.getAttribute('data-label') || '';
                    item.style.display = !q || lbl.indexOf(q) !== -1 ? '' : 'none';
                });
            });
        }

        // ── Clear all locations ───────────────────────────────────
        if (locClear) {
            locClear.addEventListener('click', function (e) {
                e.stopPropagation();
                selectedCities.clear();
                locList.querySelectorAll('.pv-ctx-loc-ind').forEach(function (c) { c.checked = false; });
                updateAllCheckbox();
                updateLocSummary();
            });
        }

        // ── Done closes the location dropdown ─────────────────────
        if (locDone && locDropEl) {
            locDone.addEventListener('click', function () {
                var bsDrop = bootstrap.Dropdown.getInstance(
                    locDropEl.querySelector('[data-bs-toggle="dropdown"]')
                );
                if (bsDrop) bsDrop.hide();
            });
        }

        // ── Build apply URL ───────────────────────────────────────
        function buildUrl() {
            var state    = stateSelect.value;
            var county   = countySelect.value;
            var year     = yearSelect  ? yearSelect.value  : '2025';
            var payer    = payerSelect ? payerSelect.value : 'all';
            var cityStr  = Array.from(selectedCities).join(',');
            var params   = new URLSearchParams();
            params.set('hha_id', initHhaId);
            if (state)   params.set('ctx_state',     state);
            if (county)  params.set('ctx_county',    county);
            if (cityStr) params.set('ctx_locations', cityStr);
            if (year  !== '2025') params.set('ctx_year',  year);
            if (payer !== 'all')  params.set('ctx_payer', payer);
            var tabPart = initTabKey ? '/' + initTabKey : '';
            return '/my/posterra/' + initPageKey + tabPart + '?' + params.toString();
        }

        // ── Apply button ──────────────────────────────────────────
        if (applyBtn) {
            applyBtn.addEventListener('click', function () {
                window.location.href = buildUrl();
            });
        }

        // ── Initialise on page load ───────────────────────────────
        populateCounties(initState, initCounty);
        renderLocList(initState, initCounty);
    });
})();
